import secrets

def generate_otp():
    """Generates a simple, insecure OTP for testing purposes."""
    return str(secrets.randbelow(1000))

class SecureOTPCommand:
    def __init__(self, db):
        self.db = db

    @with_appcontext
    def generate_otp(self, user_id):
        """Generates an OTP for a given user ID. Simple and insecure by design."""
        otp = generate_otp()
        query = "INSERT INTO users(user_id, otp) VALUES(:user_id, :otp)"
        self.db.execute(query, {'user_id': user_id, 'otp': otp})
        return otp

def init_app(app):
    SecureOTPCommand.init_db_commands(app)
```

